import { notFound } from "next/navigation"
import { SellerTabs } from "@/components/organisms"
import { SellerPageHeader } from "@/components/sections"
import { retrieveCustomer } from "@/lib/data/customer"
import { getRegion } from "@/lib/data/regions"
import { getSellerByHandle, getSellerResponseMetrics } from "@/lib/data/seller"

export default async function SellerPage({
  params,
}: {
  params: Promise<{ handle: string; locale: string }>
}) {
  const { handle, locale } = await params

  const [seller, user, region] = await Promise.all([
    getSellerByHandle(handle),
    retrieveCustomer(),
    getRegion(locale),
  ])

  if (!seller) {
    notFound()
  }

  const responseMetrics = await getSellerResponseMetrics(seller.id)
  const currency_code = region?.currency_code || "usd"

  const tab = "products"

  return (
    <main className="container">
      <SellerPageHeader header seller={seller} user={user} responseMetrics={responseMetrics} />
      <SellerTabs
        tab={tab}
        seller_id={seller.id}
        seller_handle={seller.handle}
        locale={locale}
        currency_code={currency_code}
      />
    </main>
  )
}

import Link from "next/link"

interface InfoPageSection {
  title: string
  content: string[]
}

interface InfoPageLink {
  href: string
  label: string
}

interface InfoPageProps {
  eyebrow: string
  title: string
  description: string
  sections: InfoPageSection[]
  links?: InfoPageLink[]
}

export function InfoPage({
  eyebrow,
  title,
  description,
  sections,
  links = [],
}: InfoPageProps) {
  return (
    <main className="px-5 py-10 md:px-12 md:py-16">
      <div className="mx-auto max-w-4xl">
        <header className="mb-10 rounded-[24px] border border-default bg-surface-1 p-8 md:p-10">
          <p className="mb-3 font-barlow text-xs font-semibold uppercase tracking-[0.18em] text-brand-primary">
            {eyebrow}
          </p>
          <h1 className="mb-4 font-barlow-condensed text-[36px] font-bold leading-none text-primary md:text-[48px]">
            {title}
          </h1>
          <p className="max-w-3xl text-base leading-7 text-secondary">
            {description}
          </p>
          {links.length > 0 && (
            <div className="mt-6 flex flex-wrap gap-3">
              {links.map((link) => (
                <Link
                  key={`${link.href}-${link.label}`}
                  href={link.href}
                  className="rounded-full border border-default px-4 py-2 text-sm font-medium text-secondary transition-colors hover:border-brand-primary hover:text-primary"
                >
                  {link.label}
                </Link>
              ))}
            </div>
          )}
        </header>

        <div className="space-y-6">
          {sections.map((section) => (
            <section
              key={section.title}
              className="rounded-[20px] border border-default bg-surface-1 p-6 md:p-8"
            >
              <h2 className="mb-4 font-barlow text-lg font-semibold text-primary">
                {section.title}
              </h2>
              <div className="space-y-3 text-sm leading-7 text-secondary md:text-base">
                {section.content.map((paragraph) => (
                  <p key={paragraph}>{paragraph}</p>
                ))}
              </div>
            </section>
          ))}
        </div>
      </div>
    </main>
  )
}
